// W1/W4/W5와 동일한 HMAC + nonce dedupe 로직. 수정 시 4곳 동기화 필요.
const crypto = require('crypto');

const MAX_SKEW_MS = 5 * 60 * 1000;
const GRACE_MS = 60 * 1000;
const NONCE_TTL_MS = MAX_SKEW_MS + GRACE_MS;

const item = $input.first();
const headers = (item.json && item.json.headers) || {};
const bin = item.binary && item.binary.data;
const rawBase64 = bin && bin.data;

function fail(reason) {
  return [{ json: { verified: false, reason } }];
}

if (!rawBase64) return fail('raw_body_missing');
let raw;
try {
  raw = Buffer.from(rawBase64, 'base64').toString('utf8');
} catch (e) {
  return fail('raw_body_decode_failed');
}

let body;
try {
  body = JSON.parse(raw);
} catch (e) {
  return fail('body_not_json');
}

const ts = String(headers['x-dairect-timestamp'] || '');
const nonce = String(headers['x-dairect-nonce'] || '');
const sigHeader = String(headers['x-dairect-signature'] || '');
const secret = $env.DAIRECT_WEBHOOK_SECRET || '';

if (!secret) return fail('secret_not_configured');
if (!/^[0-9]+$/.test(ts)) return fail('timestamp_missing_or_invalid');
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(nonce)) return fail('nonce_format');

const tsNum = Number(ts);
if (!Number.isFinite(tsNum)) return fail('timestamp_not_finite');
const now = Date.now();
if (Math.abs(now - tsNum) > MAX_SKEW_MS) return fail('timestamp_out_of_window');

if (!sigHeader.startsWith('sha256=')) return fail('signature_format');
const providedHex = sigHeader.slice('sha256='.length);
if (!/^[0-9a-f]{64}$/i.test(providedHex)) return fail('signature_hex_invalid');

const expected = crypto.createHmac('sha256', secret).update(`${ts}.${nonce}.${raw}`).digest('hex');
let ok = false;
try {
  const a = Buffer.from(providedHex, 'hex');
  const b = Buffer.from(expected, 'hex');
  ok = a.length === b.length && crypto.timingSafeEqual(a, b);
} catch (e) {
  ok = false;
}
if (!ok) return fail('signature_mismatch');

const staticData = $getWorkflowStaticData('global');
if (!staticData.seen || typeof staticData.seen !== 'object') staticData.seen = {};
for (const k of Object.keys(staticData.seen)) {
  if (now - staticData.seen[k] > NONCE_TTL_MS) delete staticData.seen[k];
}
if (staticData.seen[nonce]) return fail('replay_detected');
staticData.seen[nonce] = now;

return [{ json: { verified: true, body } }];

// W2 Compose Email — 연체 청구서 알림 (PM + Client).
// PII: pmEmail/clientEmail(SMTP To), invoiceNumber/projectName/amount(HTML/Subject).
// 방어: stripCtrl + escHtml + encodeURIComponent. W4/W5와 stripCtrl 로직 통일 (space replace).
function escHtml(s) {
  return String(s == null ? '' : s).replace(/[&<>"']/g, (ch) => (
    { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[ch]
  ));
}
function stripCtrl(s) {
  return String(s == null ? '' : s).replace(/[\u0000-\u001F\u007F]/g, ' ');
}

const d = ($json && $json.body && $json.body.data) || {};
const pmEmail = stripCtrl(d.pmEmail || '');
const clientEmail = stripCtrl(d.clientEmail || '');
const invoiceId = stripCtrl(d.invoiceId || '');
const invoiceNumber = stripCtrl(d.invoiceNumber || '');
const projectName = stripCtrl(d.projectName || '프로젝트');
const clientCompanyName = stripCtrl(d.clientCompanyName || '');
const totalAmount = Number(d.totalAmount || 0);
const dueDate = stripCtrl(d.dueDate || '');
const daysOverdue = Number(d.daysOverdue || 0);
const bankName = stripCtrl(d.bankName || '');
const accountNumber = stripCtrl(d.accountNumber || '');

const baseRaw = $env.DAIRECT_DASHBOARD_BASE_URL || 'https://dairect.kr';
const baseUrl = baseRaw.endsWith('/') ? baseRaw.slice(0, -1) : baseRaw;
const dashboardUrl = `${baseUrl}/dashboard/invoices/${encodeURIComponent(invoiceId)}`;
const amountFmt = totalAmount.toLocaleString('ko-KR');

const items = [];

// PM용 — 연체 확인 + 고객 연락 안내
if (pmEmail) {
  const pmSubject = stripCtrl(`[${projectName}] 청구서 ${invoiceNumber} 결제 기한 경과 (D+${daysOverdue})`);
  const pmHtml = `<!doctype html><html><body style="font-family:-apple-system,Pretendard,sans-serif;line-height:1.6;color:#111827;max-width:560px;margin:0 auto;padding:24px;">` +
    `<h1 style="font-size:20px;margin:0 0 16px;">결제 기한이 지난 청구서가 있어요</h1>` +
    `<p style="color:#4B5563;">고객 <strong>${escHtml(clientCompanyName)}</strong>에게 발행한 청구서가 결제 기한을 넘겼습니다. 확인 후 고객에게 연락해보세요.</p>` +
    `<div style="background:#F9F9F7;padding:16px;border-radius:8px;margin:16px 0;">` +
    `<p style="margin:4px 0;"><strong>프로젝트:</strong> ${escHtml(projectName)}</p>` +
    `<p style="margin:4px 0;"><strong>청구서:</strong> ${escHtml(invoiceNumber)}</p>` +
    `<p style="margin:4px 0;"><strong>금액:</strong> ${escHtml(amountFmt)}원</p>` +
    `<p style="margin:4px 0;"><strong>기한:</strong> ${escHtml(dueDate)} (${escHtml(String(daysOverdue))}일 경과)</p>` +
    `</div>` +
    `<p style="margin:24px 0;"><a href="${escHtml(dashboardUrl)}" style="display:inline-block;background:#4F46E5;color:#ffffff;padding:10px 20px;border-radius:8px;text-decoration:none;font-weight:500;">청구서 보기 →</a></p>` +
    `<p style="margin-top:32px;color:#6B7280;font-size:13px;">— Dairect</p>` +
    `</body></html>`;
  items.push({ json: { to: pmEmail, subject: pmSubject, html: pmHtml } });
}

// 고객용 — 정중한 결제 안내
if (clientEmail) {
  const clientSubject = stripCtrl(`[${projectName}] 결제 안내`);
  const bankLine = bankName && accountNumber
    ? `<p style="margin:4px 0;"><strong>입금 계좌:</strong> ${escHtml(bankName)} ${escHtml(accountNumber)}</p>`
    : `<p style="margin:4px 0;color:#DC2626;">입금 계좌 정보는 담당자에게 문의 부탁드립니다.</p>`;
  const greetName = clientCompanyName || '고객';
  const clientHtml = `<!doctype html><html><body style="font-family:-apple-system,Pretendard,sans-serif;line-height:1.6;color:#111827;max-width:560px;margin:0 auto;padding:24px;">` +
    `<h1 style="font-size:20px;margin:0 0 16px;">결제 안내드립니다</h1>` +
    `<p>${escHtml(greetName)}님,</p>` +
    `<p style="color:#4B5563;"><strong>${escHtml(projectName)}</strong> 프로젝트 관련 청구서 <strong>${escHtml(invoiceNumber)}</strong> 결제 기한이 지났습니다. 확인 후 입금 부탁드립니다.</p>` +
    `<div style="background:#F9F9F7;padding:16px;border-radius:8px;margin:16px 0;">` +
    `<p style="margin:4px 0;"><strong>청구 금액:</strong> ${escHtml(amountFmt)}원</p>` +
    `<p style="margin:4px 0;"><strong>결제 기한:</strong> ${escHtml(dueDate)}</p>` +
    bankLine +
    `</div>` +
    `<p style="color:#4B5563;">이미 입금하셨다면 본 메일은 무시하셔도 됩니다. 문의는 회신 메일로 부탁드립니다.</p>` +
    `<p style="margin-top:32px;color:#6B7280;font-size:13px;">— Dairect</p>` +
    `</body></html>`;
  items.push({ json: { to: clientEmail, subject: clientSubject, html: clientHtml } });
}

return items;
